#include <bits/stdc++.h>using namespace std;typedef long long ll;int main() {    ll t;    cin>>t;    while(t--){        ll n;        cin>>n;        string s;        cin>>s;        set<ll> st;        int pos=0;        st.insert(pos);        while(pos<n){            if(s[pos]=='L') {                pos--;                st.insert(pos);                break;            }            else pos++;            st.insert(pos);        }        cout<<st.size()<<endl;    }}